// // This module reads data from the address specified by 'addr' on every negative edge of the clock when 'en' is high.
module top_module(clk, en, we, addr, di, dout);input clk;
input we;
input en;
input [8:0] addr;
input [7:0] di;
output [7:0] dout;

reg [7:0] RAM [511:0];
reg [7:0] dout;

always @(posedge clk)
begin
  if (en)
    begin
      if (we)
        RAM[addr]<=di;
      dout <= RAM[addr];
    end
end

endmodule
